#include <iostream>
using namespace std;

class Queue {
    int arr[100];
    int front, rear;
public:
    Queue() { front = rear = -1; }
    void enqueue(int x) {
        if(front == -1) front = 0;
        arr[++rear] = x;
    }
    void dequeue() { front++; }
    int getFront() { return arr[front]; }
};

#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* next;
};

class Queue {
    Node *front, *rear;
public:
    Queue() { front = rear = NULL; }
    void enqueue(int x) {
        Node* temp = new Node();
        temp->data = x;
        temp->next = NULL;
        if(!rear) front = rear = temp;
        else {
            rear->next = temp;
            rear = temp;
        }
    }
    void dequeue() {
        if(front) {
            Node* temp = front;
            front = front->next;
            delete temp;
        }
    }
};

#include <iostream>
using namespace std;

class CircularQueue {
    int arr[5];
    int front, rear;
public:
    CircularQueue() { front = rear = -1; }
    void enqueue(int x) {
        if((rear+1)%5 == front) return;
        if(front == -1) front = 0;
        rear = (rear+1)%5;
        arr[rear] = x;
    }
};

#include <stack>
#include <iostream>
using namespace std;

class Queue {
    stack<int> s1, s2;
public:
    void enqueue(int x) { s1.push(x); }
    void dequeue() {
        if(s2.empty()) {
            while(!s1.empty()) {
                s2.push(s1.top());
                s1.pop();
            }
        }
        s2.pop();
    }
    int front() {
        if(s2.empty()) {
            while(!s1.empty()) {
                s2.push(s1.top());
                s1.pop();
            }
        }
        return s2.top();
    }
};

#include <iostream>
#include <vector>
#include <queue>
using namespace std;

void bfs(int start, vector<int> adj[]) {
    queue<int> q;
    q.push(start);
    vector<bool> visited(100, false);
    visited[start] = true;

    while(!q.empty()) {
        int node = q.front(); q.pop();
        cout << node << " ";
        for(int neigh : adj[node]) {
            if(!visited[neigh]) {
                visited[neigh] = true;
                q.push(neigh);
            }
        }
    }
}
